#include <stdio.h>
#include <stdlib.h>

#define MAX_R 1000000
#define MAX_C 1000000

int R, C, N;
int grid[MAX_R][MAX_C];
int visited[MAX_R][MAX_C];

int bfs(int x, int y) {
    int ans = 0;
    int dx[] = {-1, 1, 0, 0};
    int dy[] = {0, 0, -1, 1};
    int queue[MAX_R*MAX_C][2];
    int front = 0, rear = 0;
    queue[rear][0] = x;
    queue[rear][1] = y;
    rear++;
    visited[x][y] = 1;
    while (front < rear) {
        int curr_x = queue[front][0];
        int curr_y = queue[front][1];
        front++;
        ans += 4;
        for (int i = 0; i < 4; i++) {
            int next_x = curr_x + dx[i];
            int next_y = curr_y + dy[i];
            if (next_x >= 0 && next_x < R && next_y >= 0 && next_y < C && grid[next_x][next_y] == 1 && !visited[next_x][next_y]) {
                ans--;
                queue[rear][0] = next_x;
                queue[rear][1] = next_y;
                rear++;
                visited[next_x][next_y] = 1;
            }
        }
    }
    return ans;
}

int main() {
    scanf("%d %d %d", &R, &C, &N);
    for (int i = 0; i < N; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        grid[x-1][y-1] = 1;
    }
    int ans = 0;
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            if (grid[i][j] == 1 && !visited[i][j]) {
                ans = (ans > bfs(i, j)) ? ans : bfs(i, j);
            }
        }
    }
    printf("%d\n", ans);
    return 0;
}

