using namespace std;

const int MAX_R = 1000000;
const int MAX_C = 1000000;

int R, C, N;
int grid[MAX_R][MAX_C];
int visited[MAX_R][MAX_C];

int bfs(int x, int y) {
    int ans = 0;
    int dx[] = {-1, 1, 0, 0};
    int dy[] = {0, 0, -1, 1};
    queue<pair<int, int>> q;
    q.push({x, y});
    visited[x][y] = 1;
    while (!q.empty()) {
        int curr_x = q.front().first;
        int curr_y = q.front().second;
        q.pop();
        ans += 4;
        for (int i = 0; i < 4; i++) {
            int next_x = curr_x + dx[i];
            int next_y = curr_y + dy[i];
            if (next_x >= 0 && next_x < R && next_y >= 0 && next_y < C && grid[next_x][next_y] == 1 && !visited[next_x][next_y]) {
                ans--;
                q.push({next_x, next_y});
                visited[next_x][next_y] = 1;
            }
        }
    }
    return ans;
}

int main() {
    cin >> R >> C >> N;
    for (int i = 0; i < N; i++) {
        int x, y;
        cin >> x >> y;
        grid[x-1][y-1] = 1;
    }
    int ans = 0;
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            if (grid[i][j] == 1 && !visited[i][j]) {
                ans = max(ans, bfs(i, j));
            }
        }
    }
    cout << ans << endl;
    return 0;
}

