import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    static final int MAX_R = 1000000;
    static final int MAX_C = 1000000;
    static int R, C, N;
    static int[][] grid = new int[MAX_R][MAX_C];
    static int[][] visited = new int[MAX_R][MAX_C];

    public static int bfs(int x, int y) {
        int ans = 0;
        int[] dx = {-1, 1, 0, 0};
        int[] dy = {0, 0, -1, 1};
        Queue<int[]> q = new LinkedList<>();
        q.add(new int[] {x, y});
        visited[x][y] = 1;
        while (!q.isEmpty()) {
            int[] curr = q.poll();
            int curr_x = curr[0];
            int curr_y = curr[1];
            ans += 4;
            for (int i = 0; i < 4; i++) {
                int next_x = curr_x + dx[i];
                int next_y = curr_y + dy[i];
                if (next_x >= 0 && next_x < R && next_y >= 0 && next_y < C && grid[next_x][next_y] == 1 && visited[next_x][next_y] == 0) {
                    ans--;
                    q.add(new int[] {next_x, next_y});
                    visited[next_x][next_y] = 1;
                }
            }
        }
        return ans;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        R = sc.nextInt();
        C = sc.nextInt();
        N = sc.nextInt();
        for (int i = 0; i < N; i++) {
            int x = sc.nextInt() - 1;
            int y = sc.nextInt() - 1;
            grid[x][y] = 1;
        }
        int ans = 0;
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                if (grid[i][j] == 1 && visited[i][j] == 0) {
                    ans = Math.max(ans, bfs(i, j));
                }
            }
        }
        System.out.println(ans);
    }
}

